ee:message.ee:set-payload:
%dw 2.0
output application/json
var resultBody = payload.result default {}
var isError = (payload.status default "") == "error"
---
{ jsonrpc: "2.0", id: vars.rpcId, result: { content: [{ "type": "text", text: write(resultBody, "application/json") }], isError: isError } }

%dw 2.0
output application/json
---
{
  tools: [
    {
      name: "find_best_buyer",
      description: "Buyer (調達担当者) を category / region で検索する。未指定なら全件。",
      inputSchema: {
        "type": "object",
        properties: {
          category:         { "type": "string" },
          region:           { "type": "string" },
          supplierGoldenId: { "type": "string" }
        },
        required: []
      }
    },
    {
      name: "send_approval_request",
      description: "承認依頼を Slack DM で送信する。",
      inputSchema: {
        "type": "object",
        properties: {
          approverId:  { "type": "string" },
          subject:     { "type": "string" },
          dueAt:       { "type": "string" },
          requesterId: { "type": "string" },
          incidentId:  { "type": "string" },
          details:     { "type": "string" }
        },
        required: ["approverId", "subject", "dueAt"]
      }
    }
  ]
}

